module top_module(
    input clk,
    input reset,    
    input j,
    input k,
    output out);parameter OFF=0, ON=1; 
    reg obf_state, next_state;

    always @(*) begin

        case(obf_state)
            OFF: next_state = (j)? ON:OFF;
            ON: next_state = (k)? OFF:ON;
        endcase
    end

    always @(posedge clk) begin

        if (reset)
            obf_state <= OFF;
        else
            obf_state <= next_state;
    end


    assign out = (obf_state == ON);

endmodule
